#include<bits/stdc++.h>
using namespace std;
struct node{
    long long v,x;
}b[1000005];
int a[100005];
long long t[1000005];
long long ans=0;
bool cmp(node aa,node bb){
    return aa.v<bb.v;
}
int main(){
    long long n;
    cin>>n;
    for(long long i=1;i<=n;i++){
        cin>>a[i];
        b[i].v=a[i];
        b[i].x=i;
    }
    sort(b+1,b+n+1,cmp);
    for(long long i=1;i<=n;i++){
        long long l=b[i].x-1;
        long long r=b[i].x+1;
        if(l==0) l=n;
        if(r==n+1) r=1;

        if(a[l]==a[b[i].x]&&a[r]!=a[b[i].x]) t[b[i].x]=t[r]+1;
        else if(a[l]!=a[b[i].x]&&a[r]==a[b[i].x]) t[b[i].x]=t[l]+1;
        else if(a[l]==a[b[i].x]&&a[r]==a[b[i].x]) t[b[i].x]=1;
        else t[b[i].x]=max(t[l],t[r])+1;
        ans+=t[b[i].x];
    }
    cout<<ans;
    return 0;
}
